class Solution:
    def convertTime(self, current, correct):
        def to_minutes(t):
            h, m = t.split(':')
            return int(h) * 60 + int(m)

        diff = to_minutes(correct) - to_minutes(current)
        INF = float('inf')
        dp = [INF] * (diff + 1)
        dp[0] = 0
        for amt in range(1, diff + 1):
            best = INF
            for coin in (1, 5, 15, 60):
                if coin <= amt and dp[amt - coin] + 1 < best:
                    best = dp[amt - coin] + 1
            dp[amt] = best
        return dp[diff]

