var convertTime = function(current, correct) {
    const toMinutes = (t) => {
        const [h, m] = t.split(':').map(Number);
        return h * 60 + m;
    };
    let diff = toMinutes(correct) - toMinutes(current);
    let ops = 0;
    for (const step of [60, 15, 5, 1]) {
        ops += Math.floor(diff / step);
        diff %= step;
    }
    return ops;
};
